fn lint_overlap_order_key(lint: &Lint) -> (usize, usize, u8, bool) {
    (
        lint.span.start,
        usize::MAX - lint.span.end,
        lint.priority,
        !lint_has_useful_suggestion(lint),
    )
}

fn lint_has_useful_suggestion(lint: &Lint) -> bool {
    lint.suggestions.iter().any(|suggestion| match suggestion {
        Suggestion::ReplaceWith(replacement) => lint.get_ch(&[]).is_empty() || !replacement.is_empty(),
        Suggestion::InsertAfter(replacement) => !replacement.is_empty(),
        Suggestion::Remove => true,
    })
}

