								ignoreLint: this.actions.ignoreLint,
							}),
						),
					)
				: [],
		);
		this.lastLintBoxes = boxes;
		this.highlights.renderLintBoxes(boxes);
		this.popupHandler.updateLintBoxes(boxes);

		this.renderRequested = false;
		this.lastBoxes = boxes;
	});
}

