fn keeps_split_words_over_spell_check() {
    let doc = Document::new_plain_english_curated("I wrote insteadof.");
    let mut linter = LintGroup::new_curated(FstDictionary::curated(), Dialect::American);

    let mut lint_map = linter.organized_lints(&doc);
    remove_overlaps_map(&mut lint_map);

    assert!(!lint_map["SplitWords"].is_empty());
    assert!(lint_map["SpellCheck"].is_empty());
}

